var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"갑자기 바이크에 타라길래 어디로 가나 했더니…….","JPN":"いきなりバイクに乗れって言われたからどこに行くのかと思えば……","ENG":"As you suddenly asked to get on the bike, I was wondering where we’re headed to...","TWN":"突然叫我上車，我還以為是要去哪……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"번화가에는 왜 온 거죠?","JPN":"繁華街には何の用ですか？","ENG":"Why did we come to the main street?","TWN":"為什麼要來大街上？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"실종자가 여기서 투숙하고 있었거든. 수도에 남은 몇 안 되는 호텔이야.","JPN":"失踪者がここに泊ってたから。首都に残る数少ないホテルだよ。","ENG":"The missing person was staying here. It is one of the few remaining hotels in the capital still standing.","TWN":"因為失蹤者曾經在這裡投宿，這裡是首都裡所剩無幾的飯店。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어……. 딴 나라에서 돈 많이 벌었나 보네.","JPN":"へえ……他の国で結構儲けたのかな。","ENG":"Huh... He must have made a lot of money abroad.","TWN":"喔……看來他在其他國家賺很多喔？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇겠지. 실력이 있으면 어디에서나 자기 한 몸 건사할 수 있으니까.","JPN":"そうでしょうね。実力さえあればどこへ行っても生きていけるし。","ENG":"Right. You’ll survive anywhere if you’re skilled enough.","TWN":"應該是吧？只要有能力，去哪都能養活自己。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"묵고 있던 방에 무슨 단서가 있을 거야.","JPN":"泊ってた部屋に何か手がかりが残ってるはず。","ENG":"There must be some clues in the room he was staying in.","TWN":"在他住宿的房間裡應該會有線索。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"혼자 다녀오세요. 전 여기서 바이크나 지키고 있을 테니까.","JPN":"お一人でどうぞ。私はここでバイクでも見守ってますから。","ENG":"You can go in alone. I’ll stay here and watch over your motorcycle.","TWN":"你自己去找吧，我在這裡顧車。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"응? 어리다고 해서 토라졌어?","JPN":"え？　幼いって言ってすねちゃった？","ENG":"What? You still sulking because I called you a child back there?","TWN":"嗯？你是因為我說你年紀小，所以在耍脾氣嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 딱히. 액면가 따지는 사람이 그쪽만 있는 것도 아니고.","JPN":"いいえ。別に。外見で評価する人はそちらだけでもないし。","ENG":"Nope. Not Exactly. Don’t jump to conclusions.","TWN":"有什麼好生氣的？會算的人可不是只有你。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저는 효율을 중시하는 편이거든요.","JPN":"私は効率を重視する方ですから。","ENG":"I just like doing things as efficiently as possible.","TWN":"我是重視效率的人。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"혹시 모를 교전에 대비해 체력을 아껴야죠. 조수 일은 정중하게 사양하겠습니다.","JPN":"もしもの交戦に備えて体力を保っておかないと。助手の仕事はご丁寧にお断りします。","ENG":"I need to save my strength for a possible confrontation. I'd like to decline your assistance.","TWN":"我要保留體力，這樣之後萬一遇到敵人才有體力開戰，請恕我拒絕當你的小助手。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"협조하지 않으면 상부에 보고할 때 네 험담을 잔뜩 써 줄게.","JPN":"協力しないと上層部に報告するとき、悪口をありったけ書いてやるけど。","ENG":"Look, if you don’t cooperate I might have to say some nasty stuff about you when I report to the top.","TWN":"你不幫忙的話，我會向長官投訴你。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"험담이라뇨?","JPN":"悪口？","ENG":"Nasty stuff?","TWN":"投訴我？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"임무에 비협조적인 것으로 보아 반란군과의 내통 가능성 있음. 한 줄이면 체포되는 마법의 문장이야.","JPN":"任務に非協力的なところから反乱軍と内通した可能性あり。一行で逮捕される魔法の文章よ。","ENG":"Uncooperative during the mission, might have potential communication with rebel forces. A magical sentence that will get you arrested in a single line.","TWN":"就說你不協助執行任務，很可能是與叛軍有勾結，簡單一句話就可以讓你被逮捕。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 이만 원대로 복귀해, 중사. 다음에 심문실에서 보자.","JPN":"では、元の部隊へ復帰しなさい、軍曹。次は尋問室でね。","ENG":"Go ahead. You can return to your squad, Sergeant. See ya in the interrogation room!","TWN":"你回去吧，中士。我們下次在審訊室見囉～"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잠깐! 잠깐 기다려 봐요! 융통성 없게 왜 그래요?","JPN":"ちょっと！　ちょっと待って！　融通が利きませんね！","ENG":"Hold on! Wait a minute! Why are you being so inflexible?","TWN":"等一下！你先等一下啦！有什麼話好好說嘛～"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"애초에 전 헌병도 아니고 일개 보병이란 말입니다. 사람 찾는 일에는 다우징보다 쓸모없어요.","JPN":"だいたい私は憲兵でもないし、ただの歩兵なんです。人探しにはダウジングより役立たずなんですよ。","ENG":"First of all, I’m not a military policeman, I’m just a soldier. I don’t know the first thing about finding people.","TWN":"我又不是憲兵，我只是個小小的步兵，找人這種事我派不上用場啦！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"상관없어. 나는 모건 같은 초인이 아니라서 한 명이라도 더 필요해.","JPN":"構わないよ。私はモーガンのような超人じゃないから一人でも多いほうがいいの。","ENG":"I don’t care. I’m not some 007 level agent like Morgan. I need the backup.","TWN":"我不在意！畢竟我不是像摩根那種超人，多一個人幫忙也好。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네가 도와 주면 좋겠어, 중사.","JPN":"君に助けてほしいんだ、軍曹。","ENG":"I need your help, Sergeant.","TWN":"中士，我希望你可以幫我。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다른 사람이 아니라, 네가.","JPN":"他の誰でもなく、君に。","ENG":"Not someone else, YOU.","TWN":"不是別人，而是你！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……그만두세요. 그런 자존감 부추기는 멘트.","JPN":"……やめてください。そんなプライドを煽るようなセリフは。","ENG":"...Enough. Stop trying to appeal to my pride with those comments.","TWN":"……好了啦，以為我不知道這是話術嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"들켰어? 너무 티났나?","JPN":"バレた？　わざとらしすぎたかな？","ENG":"Oh? Was it so obvious?","TWN":"被你發現啦？做得太明顯了嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"손발이 오글거릴 정도로요.","JPN":"もう恥ずかしいくらいですよ。","ENG":"It was a little cringy.","TWN":"不太自然。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"선동하고 싶으면 좀 더 세련된 방법도 많잖아요.","JPN":"煽りたいのならもっとシャレた方法だっていっぱいあるじゃないですか。","ENG":"There are better ways to instigate me.","TWN":"想激勵我的話，應該有其他更好的方法吧？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"꼭 선동까지 해야 돼?","JPN":"煽る必要なんかある？","ENG":"Do I really need to instigate you?","TWN":"有需要激勵你嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"일단은 중사도 명령을 받은 입장이잖아? 그렇다면 군인답게 성실히 임해야지.","JPN":"一応は軍曹も命令された立場でしょう？　それなら軍人らしく真面目に向き合わないと。","ENG":"I mean, Sergeant, you’re a soldier. Isn’t it your job to act like one?","TWN":"你也是臨危受命不是嗎？那就該像個軍人一樣，忠心地執行任務吧？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"우격다짐으로 끌려 온 사람한테 그런 말씀을 하셔도 말이죠…….","JPN":"無理やり連れてこられた人にそんなこと言ってもですね……","ENG":"I mean, saying that to someone who was practically dragged here by force...","TWN":"我又不是自願來的，說這種話也……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아니, 그냥 이쯤 하죠. 따라가긴 하겠지만 딱히 뭔가 기대하진 마세요.","JPN":"いや、このくらいにしておきましょう。付いては行きますけど、別に期待なんかはしないでください。","ENG":"Fine. Whatever. I guess I’ll play along but don’t expect anything from me.","TWN":"算了，就這樣吧！我會跟你去，但你不要有所期待。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"음? 갑자기 마음이 바뀐 거야?","JPN":"うん？　いきなり気が変わった？","ENG":"Oh? A sudden change of heart?","TWN":"嗯？怎麼突然改變心意啦？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"생각해 보니 남들과 대화로 견해차를 좁힐 수 있다는 망상은 사춘기 때 졸업했었거든요.","JPN":"考えてみたら、話して見解の相違を解消できるって妄想は思春期に卒業したんでした。","ENG":"On second thought, I don't hold on to the delusion anymore that having genuine conversation with someone would narrow our differences.","TWN":"因為我突然想起來，從我青春期之後，就不再妄想可以用對話的方式來縮小歧見。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"너도 참 세상 바라보는 눈이 삐딱하구나. 재밌는 성격이네.","JPN":"君もひねくれてるね。面白い性格だよ。","ENG":"Looks like you have a pretty perverse worldview too. What a funny personality.","TWN":"看來你也是思想很扭曲呢，真有意思～"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"자기 능력을 과신하면 죽는 곳이니까요. 이 나라는.","JPN":"自分の能力を信じすぎると死ぬところなんです。この国は。","ENG":"This country. The land where you die if you’re overconfident in your abilities.","TWN":"畢竟在這個國家，對自己的能力太有自信就是必死無疑。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데 모건은 누구죠? 직장 동료?","JPN":"ていうか、モーガンって誰ですか？　職場の仲間？","ENG":"Wait, who is Morgan? A coworker?","TWN":"不過摩根是誰？你的同事？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"전설적인 첩보원. 이 바닥에서는 신출내기도 들어봤을 만큼 유명한 이름이야.","JPN":"伝説的な諜報員。この業界では新米も聞いたことがあるくらい有名な名前だよ。","ENG":"A legendary spy. In my business, even a complete rookie has heard of him.","TWN":"是傳說中的情報員，有名到連新人都聽說過他的名字。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"유명한 첩보원이라니 평화로운 그로니아 같은 소리네요.","JPN":"有名な諜報員だなんて、平和なグロニアみたいな表現ですね。","ENG":"Ha! A famous spy? That’s like saying peaceful Gronia.","TWN":"有名的情報員嗎？果然是處於亂世的格羅尼亞。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HOTEL_GRONIA_NULL_NPC","text":{"KOREA":"어서 오세요. 방을 예약하셨나요?","JPN":"いらっしゃいませ。ご予約なさっていますか？","ENG":"Welcome! Do you have a reservation?","TWN":"歡迎光臨，請問有預約嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"친척 분 부탁으로 방에서 필요한 물건을 챙기러 왔어요.","JPN":"親戚の頼みで部屋から必要なものを取りに来ました。","ENG":"A relative staying here asked me to come by and pick up a few things from their room.","TWN":"親戚拜託我去他的房間裡幫他拿東西。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"요제프 클림트라는 분인데, 일 때문에 며칠 동안 여기 못 오셨다고 하더라고요.","JPN":"ヨセフ・クリムトと言いますが、仕事上しばらくここに来れなかったらしくて。","ENG":"The name is Yosef Klimt, and he is away for a few days because of work.","TWN":"他叫約瑟·克里姆，他說他有事要處理，會有幾天無法回來這裡。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HOTEL_GRONIA_NULL_NPC","text":{"KOREA":"아. 클림트님이군요. 401호실입니다. 4층 오른쪽 복도 끝에 있는 방이에요.","JPN":"あ、クリムト様でございますね。401号室です。4階の右の廊下、一番奥の部屋でございます。","ENG":"Ah, Mr. Klimt. Room 401. The room is on the 4th floor, at the end of the hallway on your right.","TWN":"喔～是克里姆先生嗎？他住在401號，房間在4樓右邊走廊的盡頭。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOTEL_GRONIA_NULL_NPC","text":{"KOREA":"직원이 드나드는 걸 싫어하셔서 안이 조금 어수선할 수도 있어요. 열쇠는 받아 오셨나요?","JPN":"スタッフの出入りを嫌厭されましたので、中が少々散らかっていると思います。鍵はお持ちですか？","ENG":"There’s been a do not disturb sign, so the staff haven’t been inside to clean. It might be a bit messy. Do you already have a key?","TWN":"因為他說不希望有人打擾他，所以房間內可能會有點凌亂，請問你有鑰匙嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"401호라…….","JPN":"401号室ね……","ENG":"Room 401, you say...","TWN":"401號……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼요. 알려 줘서 고마워요.","JPN":"もちろんです。教えてくれてありがとう。","ENG":"A key? Yes of course. Thank you for your help.","TWN":"當然有，謝謝你。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"열쇠는 언제 챙겨 온 거예요?","JPN":"鍵はいつの間に持ってきたんですか？","ENG":"Hey, when did we get a room key?","TWN":"你是什麼時候拿到鑰匙的？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"없어도 괜찮아. 우리나라는 여전히 구식 자물쇠를 쓰거든.","JPN":"なくてもいいよ。この国はいまだに古い錠を使ってるから。","ENG":"It doesn’t matter without a key. This country still uses old-fashioned locks.","TWN":"沒有鑰匙也無所謂，我們國家用的都是舊式的鎖頭。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"공작원이 좀도둑도 아니고 자물쇠 따는 법을 알아요?","JPN":"工作員がコソ泥でもなし、なんで錠の開け方を知ってるんですか？","ENG":"You’re a secret agent, not some petty thief, but you know how to pick a lock?","TWN":"特務又不是小偷，竟然還會開鎖喔？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"넌 의사도 아니면서 사람 머리통 따는 법을 알잖아.","JPN":"君もお医者さんじゃないのに、人の頭のフタを開ける方法を知ってるじゃない。","ENG":"And you’re not a doctor yet you know still how to amputate someone’s head.","TWN":"你也不是醫生，還不是知道怎麼摘人家的腦袋瓜？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"칫…….","JPN":"ちっ……","ENG":"Tch...","TWN":"嘖……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"다 큰 어른이 혼자 쓰는 방치고는 되게 어지럽혀 놨네요.","JPN":"大の大人が一人で使う部屋にしてはすごく散らかってますね。","ENG":"It’s pretty messy here for just one person living alone.","TWN":"以一個成熟大人的房間來說，他的房間亂得有點誇張。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러게. 여행용 트렁크도 열어 놓고 간 걸 봐선 꽤 급하게 나간 모양이야.","JPN":"そうね。トランクまで開けっ放しにしたところを見ると結構急いで出ていったみたい。","ENG":"Yeah. His suitcase is open, looks like he left in a hurry.","TWN":"對啊，而且他的旅行箱還開著，看來是走得很匆促。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"자, 그러면 시작할까? 오래 있으면 의심 받을 테니 서두르자.","JPN":"さ、それじゃ始めようか？　長居すると疑われるだろうし、急ごう。","ENG":"Okay. Let’s get started. If we take too long it’ll be suspicious. Hurry up.","TWN":"那就開始吧？待太久會讓人起疑，動作快！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"보안국 일 때문에 왔다고 하면 며칠 동안 눌러앉아 있어도 되잖아요?","JPN":"保安局の仕事で来たって言えば、何日居座ってもいいんじゃないですか？","ENG":"If we just said we’re from the Department of National Security, we could stay here as long as we want, right?","TWN":"只要說我們是安全局派來的，你愛在這邊待多久都可以吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러다가 지휘자가 실종되었다는 소문이 퍼지면 이번 건은 실패야.","JPN":"それで指揮者が行方不明になったって噂が広がれば今度の件は失敗だよ。","ENG":"If we did that and it gets out that the conductor went missing, this mission would be a failure.","TWN":"這樣指揮家失蹤的消息就會曝光，那我們就算任務失敗！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"개인 소지품으로 보이는 건 전부 확인해. 조금이라도 눈에 띄는 게 있으면 얘기해 줘.","JPN":"私物に見えるものは全部確認。少しでも目につく物があれば言って。","ENG":"Check his personal belongings. Tell me if anything sticks out to you.","TWN":"他的個人物品全都確認過一遍，只要發現任何可能藏有線索的東西就跟我說。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"눈에 띄는 거라고 해도……. 예를 들면요?","JPN":"目につく物って言われても……例えば？","ENG":"Something that sticks out... Like what?","TWN":"什麼是藏有線索的東西……可以舉個例嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"서류, 영수증이나 따로 쓰는 세면도구처럼. 침대 밑도 샅샅이 찾아 봐.","JPN":"書類、領収書や他人用の洗面道具みたいな物。ベッドの下もくまなく探して。","ENG":"Just check all documents, receipts, even toiletries. Check under the bed too.","TWN":"像是資料、發票，或是個人盥洗用品這類的東西，或是床鋪底下，這些都不能放過！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"굉장히 시시콜콜한 것들이네요.","JPN":"めちゃくちゃくだらないものだらけですね。","ENG":"Those things don’t sound all that important.","TWN":"都是些雞毛蒜皮的事呢！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"시시콜콜할수록 그 사람의 본성이 드러나거든.","JPN":"くだらないほどその人の本性が出るから。","ENG":"Even the little things give us clues as to the type of person he is.","TWN":"就是要透過這些雞毛蒜皮的事，才能發現那個人真正的樣子。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이런 것처럼 말이야.","JPN":"これみたいに。","ENG":"Here, something like this.","TWN":"就像這個一樣。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"보안국은 장롱 안에다 정장을 걸어 둔 거에도 의미를 부여하나요?","JPN":"保安局ってタンスの中に掛けてあるスーツにも意味を与えるんですか？","ENG":"The National Security thinks the way suits are hung in a closet is important?","TWN":"安全局對於掛在衣櫃裡的西裝，也有不同的解讀嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니. 여기 옷 사이를 봐. 머리카락이 걸려 있지?","JPN":"ほら。服と服の間を見て。髪の毛が挟まってるでしょ？","ENG":"Look closely. You see the hair hanging between these clothes?","TWN":"不，你看這件衣服，上面有頭髮對吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이러면 머리카락이 떨어진 걸 보고 다른 사람이 건드렸는지 알 수 있어.","JPN":"これで、髪の毛が落ちたのを見て、他の誰かが触ったかどうかがわかるんだ。","ENG":"You can tell he placed it here on purpose. If it falls, he’ll know someone has tampered with it.","TWN":"有頭髮掉在上面，就表示很可能有人碰過。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"굉장히 강박적인 성격이거나……. 평범한 지휘자는 아닌가 보네.","JPN":"すごく強迫的な性格だとか……ただの指揮者ではなさそうね。","ENG":"Seems like he has OCD... I guess he’s no ordinary conductor.","TWN":"他可能有強迫症……感覺不是普通的指揮家。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……글쎄요. 제 눈에는 그냥 자연스럽게 빠진 머리카락으로 보이는데요.","JPN":"……さあ。私にはただ自然に抜けた髪の毛にしか見えませんけど。","ENG":"...Well, I don’t know. Looks like just natural hair shedding to me.","TWN":"……我哪知道，在我看來，就是自然的掉髮。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어쨌거나 단서만 찾으면 되는 거죠?","JPN":"とにかく手がかりさえ探せばいいんですね？","ENG":"Anyways, I just need to look for clues right?","TWN":"總之就是要找到線索對吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"소리가 들린 곳은……. 이 서랍장 아래인데…….","JPN":"音が聞こえたのは……このタンスの下なんだけど……","ENG":"I hear something... Under the drawers...","TWN":"發出聲音的地方……在這個抽屜底下……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으음. 틈이 너무 좁잖아.","JPN":"ううん。狭すぎ。","ENG":"Ngh... The spacing is too tight.","TWN":"呃，縫隙未免也太窄！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어디……. 종이로 이렇게, 이렇게 건드리며언…….","JPN":"どれ……紙でこう、こういじるとぉ……","ENG":"Let’s see... This piece of paper, maybe it could fit underneath and...","TWN":"看我的……只要拿紙這樣，再這樣撈……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"후우. 빠졌다.","JPN":"ふう。抜けた。","ENG":"Phew. Got it.","TWN":"呼～出來啦！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이건……. 사진인가?","JPN":"これは……写真かな？","ENG":"What’s this...a picture?","TWN":"這個是……照片？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"응? 사진? 잠깐 보여 줄래?","JPN":"うん？　写真？　ちょっと見せて。","ENG":"What? What picture? Here, let me see!","TWN":"什麼照片？可以借我看一下嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"폴라로이드네. 그런데 이 사람은…….","JPN":"ポラロイドだね。でも、この人……","ENG":"Oh, a polaroid. Wait a second, that’s...","TWN":"是拍立得拍的照片，不過旁邊的人是……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아는 여자예요?","JPN":"この女、知ってるんですか？","ENG":"You know her?","TWN":"這個女生你認識嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"일단은. 왜 찍혀 있는지는 직접 들어 봐야 할 것 같지만.","JPN":"一応は。なんで写ってるのかは本人に聞くしかないけど。","ENG":"Yes. Will have to ask her why she’s in the picture, though.","TWN":"認識是認識，至於他們為何會一起合照，我必須親口問她。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그런데 이건 어디서 찾은 거야?","JPN":"って、これはどこにあったの？","ENG":"Where did you find this?","TWN":"你這是在哪裡找到的？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"서랍장 밑에서요. 급하게 나가려다 틈새로 빠뜨린 거겠죠.","JPN":"タンスの下です。急いで出る際に狭間に落としたんでしょう。","ENG":"Underneath the drawers. It must have slipped out and fallen under the drawers as he was leaving.","TWN":"抽屜底下，應該是因為走的時候太匆忙，所以才掉到縫隙裡吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"흐음……. 그런 부주의한 사람은 아닌 것 같지만…….","JPN":"ふうん……そんなに不注意な人ではなさそうだけど……","ENG":"Hmm... He doesn’t seem like such a careless person but...","TWN":"嗯嗯……但他感覺不像是這種粗心大意的人……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"우선 연락해 봐야겠네. 당장은 다른 단서도 없으니까.","JPN":"まず連絡してみないと。今は他に手がかりがないから。","ENG":"Okay, I’ll need to contact her first. We don’t have any other leads to go off.","TWN":"我先打電話問問吧！反正現在也找不到其他線索。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"분위기에 휩쓸려서 동행하기는 했는데……. 나중에라도 국경 넘을 수 있으려나, 이거.","JPN":"雰囲気に流されて同行はしたけど……後にでも国境を超えられるのかな、これ。","ENG":"Well, seems I’ve been swept up in the moment…I'm worried I can sneak across the border later.","TWN":"剛剛一時衝動答應和她一起行動……這樣我之後還能穿越國界嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"보안국이랑 엮였다는 게 들키면 브로커들이 순순히 거래해 줄 리가 없는데……. 하우으…….","JPN":"保安局と絡んだってことがバレたら、ブローカーが素直に取引に乗ってくれるわけもないし……はうぅ……","ENG":"If the smugglers find out I’m affiliated with the National Security, there’s no way they will help me... Ugh...","TWN":"要是被人蛇仲介發現我和安全局的人合作過，他們應該就不會想和我交易吧……哀哀……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_QM","text":{"KOREA":"찾았다.","JPN":"見つけた。","ENG":"Found it.","TWN":"找到了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};